  KEY `assessment_auto_referrals_visit_id_foreign` (`visit_id`),
  KEY `assessment_auto_referrals_acknowledged_by_foreign` (`acknowledged_by`),
  KEY `assessment_auto_referrals_service_point_status_index` (`service_point`,`status`),
  KEY `assessment_auto_referrals_client_id_status_index` (`client_id`,`status`),
  KEY `assessment_auto_referrals_status_index` (`status`),
  CONSTRAINT `assessment_auto_referrals_acknowledged_by_foreign` FOREIGN KEY (`acknowledged_by`) REFERENCES `users` (`id`),
  CONSTRAINT `assessment_auto_referrals_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`),
  CONSTRAINT `assessment_auto_referrals_form_response_id_foreign` FOREIGN KEY (`form_response_id`) REFERENCES `assessment_form_responses` (`id`) ON DELETE CASCADE,
  CONSTRAINT `assessment_auto_referrals_visit_id_foreign` FOREIGN KEY (`visit_id`) REFERENCES `visits` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


