  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `assessment_form_responses_branch_id_foreign` (`branch_id`),
  KEY `assessment_form_responses_created_by_foreign` (`created_by`),
  KEY `assessment_form_responses_updated_by_foreign` (`updated_by`),
  KEY `assessment_form_responses_form_schema_id_status_index` (`form_schema_id`,`status`),
  KEY `assessment_form_responses_client_id_form_schema_id_index` (`client_id`,`form_schema_id`),
  KEY `assessment_form_responses_visit_id_status_index` (`visit_id`,`status`),
  KEY `assessment_form_responses_created_at_index` (`created_at`),
  KEY `assessment_form_responses_status_index` (`status`),
  CONSTRAINT `assessment_form_responses_branch_id_foreign` FOREIGN KEY (`branch_id`) REFERENCES `branches` (`id`),
  CONSTRAINT `assessment_form_responses_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE,
  CONSTRAINT `assessment_form_responses_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`),
  CONSTRAINT `assessment_form_responses_form_schema_id_foreign` FOREIGN KEY (`form_schema_id`) REFERENCES `assessment_form_schemas` (`id`) ON DELETE CASCADE,
  CONSTRAINT `assessment_form_responses_updated_by_foreign` FOREIGN KEY (`updated_by`) REFERENCES `users` (`id`),
  CONSTRAINT `assessment_form_responses_visit_id_foreign` FOREIGN KEY (`visit_id`) REFERENCES `visits` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

