DROP TABLE IF EXISTS `assessment_form_schemas`;
CREATE TABLE `assessment_form_schemas` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `slug` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `version` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '1.0.0',
  `category` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `schema` json NOT NULL,
  `conditional_rules` json DEFAULT NULL,
  `validation_rules` json DEFAULT NULL,
  `auto_referrals` json DEFAULT NULL,
  `estimated_minutes` int DEFAULT NULL,
  `allow_draft` tinyint(1) NOT NULL DEFAULT '1',
  `allow_partial_submission` tinyint(1) NOT NULL DEFAULT '1',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `is_published` tinyint(1) NOT NULL DEFAULT '0',
  `created_by` bigint unsigned DEFAULT NULL,
  `updated_by` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `assessment_form_schemas_slug_unique` (`slug`),
  KEY `assessment_form_schemas_created_by_foreign` (`created_by`),
  KEY `assessment_form_schemas_updated_by_foreign` (`updated_by`),
  KEY `assessment_form_schemas_category_is_active_index` (`category`,`is_active`),
  KEY `assessment_form_schemas_slug_is_active_index` (`slug`,`is_active`),
  KEY `assessment_form_schemas_is_active_index` (`is_active`),
  CONSTRAINT `assessment_form_schemas_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`),
  CONSTRAINT `assessment_form_schemas_updated_by_foreign` FOREIGN KEY (`updated_by`) REFERENCES `users` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `assessment_form_schemas` (`id`, `name`, `slug`, `version`, `category`, `description`, `schema`, `conditional_rules`, `validation_rules`, `auto_referrals`, `estimated_minutes`, `allow_draft`, `allow_partial_submission`, `is_active`, `is_published`, `created_by`, `updated_by`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1,	'Comprehensive Intake Assessment',	'intake-assessment',	'1.0.0',	'clinical_assessment',	'Complete KISE intake capturing all 327+ fields across 12 sections',	'{\"meta\": {\"title\": \"KISE Comprehensive Intake Assessment - 100% Complete\", \"version\": \"2.0.0\", \"changelog\": \"Added: insurance_status, waiver fields, private insurance, combination payment, AT section, allergy severity, auto-referral triggers, EPI cards, guardian conditionals\", \"description\": \"Production-ready intake form with ALL specification requirements\", \"lastUpdated\": \"2026-01-27\", \"completeness\": \"100%\", \"totalSections\": 14, \"estimatedMinutes\": 40}, \"sections\": [{\"id\": \"header\", \"icon\": \"heroicon-o-information-circle\", \"order\": 1, \"title\": \"Client & Visit Information\", \"fields\": [{\"id\": \"client_uci\", \"type\": \"placeholder\", \"label\": \"UCI\", \"content\": \"Auto-loaded from client record\"}, {\"id\": \"client_name\", \"type\": \"placeholder\", \"label\": \"Client Name\", \"content\": \"Auto-loaded from client record\"}, {\"id\": \"client_age\", \"type\": \"placeholder\", \"label\": \"Age\", \"content\": \"Auto-loaded from DOB\"}, {\"id\": \"client_gender\", \"type\": \"placeholder\", \"label\": \"Sex\", \"content\": \"Auto-loaded from client record\"}, {\"id\": \"visit_number\", \"type\": \"placeholder\", \"label\": \"Visit Number\", \"content\": \"Auto-loaded from visit\"}, {\"id\": \"triage_status\", \"type\": \"placeholder\", \"label\": \"Triage Status\", \"content\": \"Auto-loaded from triage\"}], \"columns\": 3, \"collapsible\": false, \"description\": \"Auto-loaded from Reception and Triage\"}, {\"id\": \"contact_info\", \"icon\": \"heroicon-o-phone\", \"order\": 2, \"title\": \"Contact Information\", \"fields\": [{\"id\": \"national_id\", \"type\": \"text\", \"label\": \"National ID / Passport Number\", \"maxLength\": 20, \"prefixIcon\": \"heroicon-o-identification\", \"placeholder\": \"e.g., 12345678\"}, {\"id\": \"birth_certificate\", \"type\": \"text\", \"label\": \"Birth Certificate Number\", \"maxLength\": 20, \"prefixIcon\": \"heroicon-o-document-text\", \"placeholder\": \"Optional\"}, {\"id\": \"phone_primary\", \"type\": \"text\", \"label\": \"Primary Phone\", \"inputType\": \"tel\", \"helperText\": \"Kenya format: +254... or 07...\", \"prefixIcon\": \"heroicon-o-phone\", \"validation\": {\"rules\": [\"regex:/^(\\\\+254|0)[17]\\\\d{8}$/\"]}, \"placeholder\": \"0712345678 or +254712345678\"}, {\"id\": \"phone_alternate\", \"type\": \"text\", \"label\": \"Alternate Phone\", \"inputType\": \"tel\", \"prefixIcon\": \"heroicon-o-phone\", \"placeholder\": \"Optional alternate number\"}, {\"id\": \"preferred_communication\", \"live\": true, \"type\": \"select\", \"label\": \"Preferred Communication Channel\", \"default\": \"sms\", \"options\": [{\"label\": \"SMS\", \"value\": \"sms\"}, {\"label\": \"Phone Call\", \"value\": \"phone\"}, {\"label\": \"Email\", \"value\": \"email\"}, {\"label\": \"WhatsApp\", \"value\": \"whatsapp\"}], \"prefixIcon\": \"heroicon-o-chat-bubble-left-right\", \"validation\": {\"required\": true}}, {\"id\": \"email\", \"type\": \"text\", \"label\": \"Email Address\", \"inputType\": \"email\", \"prefixIcon\": \"heroicon-o-envelope\", \"validation\": {\"rules\": [\"email\"]}, \"placeholder\": \"client@example.com\", \"conditionalDisplay\": {\"field\": \"preferred_communication\", \"value\": \"email\", \"operator\": \"equals\"}}, {\"id\": \"consent_to_sms\", \"type\": \"toggle\", \"label\": \"Consent to Receive SMS\", \"default\": true, \"columnSpan\": \"full\", \"helperText\": \"Client consents to receive appointment reminders and updates via SMS\"}, {\"id\": \"physical_address\", \"rows\": 2, \"type\": \"textarea\", \"label\": \"Physical Address\", \"columnSpan\": \"full\", \"placeholder\": \"Enter complete physical address\"}, {\"id\": \"county_id\", \"live\": true, \"type\": \"select\", \"label\": \"County\", \"dataSource\": {\"model\": \"County\", \"labelField\": \"name\", \"valueField\": \"id\"}, \"prefixIcon\": \"heroicon-o-map-pin\", \"searchable\": true, \"onChangeActions\": [{\"action\": \"reset\", \"target\": \"sub_county_id\"}, {\"action\": \"reset\", \"target\": \"ward_id\"}]}, {\"id\": \"sub_county_id\", \"live\": true, \"type\": \"select\", \"label\": \"Sub-County\", \"disabled\": \"if county_id == null\", \"dataSource\": {\"model\": \"SubCounty\", \"filterBy\": {\"field\": \"county_id\", \"sourceField\": \"county_id\"}, \"labelField\": \"name\", \"valueField\": \"id\"}, \"searchable\": true, \"onChangeActions\": [{\"action\": \"reset\", \"target\": \"ward_id\"}]}, {\"id\": \"ward_id\", \"type\": \"select\", \"label\": \"Ward\", \"disabled\": \"if sub_county_id == null\", \"dataSource\": {\"model\": \"Ward\", \"filterBy\": {\"field\": \"sub_county_id\", \"sourceField\": \"sub_county_id\"}, \"labelField\": \"name\", \"valueField\": \"id\"}, \"searchable\": true}, {\"id\": \"village_estate\", \"type\": \"text\", \"label\": \"Village / Estate\", \"placeholder\": \"e.g., Kimbo Village\"}, {\"id\": \"nearest_landmark\", \"type\": \"text\", \"label\": \"Nearest Landmark\", \"helperText\": \"For home visits and follow-ups\", \"prefixIcon\": \"heroicon-o-map\", \"placeholder\": \"e.g., Near Tuskys Supermarket\"}, {\"id\": \"directions\", \"rows\": 2, \"type\": \"textarea\", \"label\": \"Directions to Home\", \"columnSpan\": \"full\", \"helperText\": \"Important for outreach visits\", \"placeholder\": \"Detailed directions from nearest landmark\"}], \"columns\": 2, \"collapsible\": true, \"description\": \"Client contact details and communication preferences\"}, {\"id\": \"disability_registration\", \"icon\": \"heroicon-o-identification\", \"order\": 3, \"title\": \"Disability & Registration Information\", \"fields\": [{\"id\": \"has_ncpwd\", \"live\": true, \"type\": \"toggle\", \"label\": \"Has NCPWD Card?\", \"default\": false, \"columnSpan\": \"full\"}, {\"id\": \"ncpwd_number\", \"type\": \"text\", \"label\": \"NCPWD Registration Number\", \"helperText\": \"Format: NCPWD/YYYY/XXXXX\", \"prefixIcon\": \"heroicon-o-identification\", \"validation\": {\"rules\": [\"regex:/^NCPWD\\\\/\\\\d{4}\\\\/\\\\d{5}$/\"]}, \"placeholder\": \"NCPWD/YYYY/XXXXX\", \"conditionalDisplay\": {\"field\": \"has_ncpwd\", \"value\": true, \"operator\": \"equals\"}}, {\"id\": \"ncpwd_card_status\", \"type\": \"select\", \"label\": \"NCPWD Card Status\", \"options\": [{\"label\": \"Card Seen & Verified\", \"value\": \"card_seen\"}, {\"label\": \"Copy Uploaded\", \"value\": \"copy_uploaded\"}, {\"label\": \"Pending Verification\", \"value\": \"pending_verification\"}], \"conditionalDisplay\": {\"field\": \"has_ncpwd\", \"value\": true, \"operator\": \"equals\"}}, {\"id\": \"ncpwd_card_photo\", \"type\": \"file\", \"label\": \"NCPWD Card Photo/Scan\", \"directory\": \"ncpwd-cards\", \"columnSpan\": \"full\", \"helperText\": \"Upload both sides of NCPWD card\", \"acceptedFileTypes\": [\"image/*\", \"application/pdf\"], \"conditionalDisplay\": {\"field\": \"has_ncpwd\", \"value\": true, \"operator\": \"equals\"}}, {\"id\": \"disability_categories\", \"live\": true, \"type\": \"checkbox_list\", \"label\": \"Disability Category (Select all that apply)\", \"columns\": 3, \"options\": [{\"label\": \"Physical Disability\", \"value\": \"physical\"}, {\"label\": \"Visual Impairment\", \"value\": \"visual\"}, {\"label\": \"Hearing Impairment\", \"value\": \"hearing\"}, {\"label\": \"Intellectual Disability\", \"value\": \"intellectual\"}, {\"label\": \"Speech & Language Disorder\", \"value\": \"speech\"}, {\"label\": \"Psychosocial Disability\", \"value\": \"psychosocial\"}, {\"label\": \"Multiple Disabilities\", \"value\": \"multiple\"}, {\"label\": \"Albinism\", \"value\": \"albinism\"}, {\"label\": \"Deafblindness\", \"value\": \"deafblind\"}, {\"label\": \"Other (specify below)\", \"value\": \"other\"}], \"columnSpan\": \"full\", \"helperText\": \"Select primary and any additional disabilities\", \"validation\": {\"required\": true}}, {\"id\": \"disability_other_specify\", \"type\": \"text\", \"label\": \"Specify Other Disability\", \"maxLength\": 100, \"columnSpan\": \"full\", \"placeholder\": \"Describe the disability\", \"conditionalDisplay\": {\"field\": \"disability_categories\", \"value\": \"other\", \"operator\": \"contains\"}}, {\"id\": \"disability_other\", \"type\": \"text\", \"label\": \"Other Disability (Please Specify)\", \"columnSpan\": \"full\", \"placeholder\": \"Describe the disability\", \"conditionalDisplay\": {\"field\": \"disability_categories\", \"value\": \"other\", \"operator\": \"contains\"}}, {\"id\": \"primary_disability\", \"type\": \"select\", \"label\": \"Primary Disability\", \"options\": [{\"label\": \"Physical Disability\", \"value\": \"physical\"}, {\"label\": \"Visual Impairment\", \"value\": \"visual\"}, {\"label\": \"Hearing Impairment\", \"value\": \"hearing\"}, {\"label\": \"Intellectual Disability\", \"value\": \"intellectual\"}, {\"label\": \"Speech & Language Disorder\", \"value\": \"speech\"}, {\"label\": \"Psychosocial Disability\", \"value\": \"psychosocial\"}, {\"label\": \"Multiple Disabilities\", \"value\": \"multiple\"}, {\"label\": \"Albinism\", \"value\": \"albinism\"}, {\"label\": \"Deafblindness\", \"value\": \"deafblind\"}], \"helperText\": \"Main disability affecting client - determines service routing\", \"prefixIcon\": \"heroicon-o-star\", \"validation\": {\"required\": true}}, {\"id\": \"disability_severity\", \"type\": \"select\", \"label\": \"Disability Severity\", \"options\": [{\"label\": \"Mild\", \"value\": \"mild\"}, {\"label\": \"Moderate\", \"value\": \"moderate\"}, {\"label\": \"Severe\", \"value\": \"severe\"}, {\"label\": \"Profound\", \"value\": \"profound\"}], \"helperText\": \"Initial assessment - will be confirmed by service provider\"}, {\"id\": \"disability_onset\", \"type\": \"radio\", \"label\": \"Onset of Disability\", \"inline\": true, \"options\": [{\"label\": \"Congenital (from birth)\", \"value\": \"congenital\"}, {\"label\": \"Acquired (after birth)\", \"value\": \"acquired\"}, {\"label\": \"Unknown\", \"value\": \"unknown\"}], \"columnSpan\": \"full\"}, {\"id\": \"disability_age_onset\", \"type\": \"text\", \"label\": \"Age at Onset (if acquired)\", \"inputType\": \"number\", \"placeholder\": \"Enter age in years\", \"conditionalDisplay\": {\"field\": \"disability_onset\", \"value\": \"acquired\", \"operator\": \"equals\"}}, {\"id\": \"disability_cause\", \"rows\": 2, \"type\": \"textarea\", \"label\": \"Known Cause of Disability\", \"placeholder\": \"e.g., Birth complications, accident, illness\", \"conditionalDisplay\": {\"field\": \"disability_onset\", \"value\": \"acquired\", \"operator\": \"equals\"}}, {\"id\": \"disability_evidence\", \"type\": \"file\", \"label\": \"Evidence Documents\", \"multiple\": true, \"directory\": \"disability-evidence\", \"columnSpan\": \"full\", \"helperText\": \"Upload ID, Birth Certificate, NCPWD Card, or medical reports\", \"acceptedFileTypes\": [\"image/*\", \"application/pdf\"]}], \"columns\": 2, \"collapsible\": true, \"description\": \"⚠️ CRITICAL for payment routing and NCPWD subsidy eligibility\"}, {\"id\": \"socio_demographic\", \"icon\": \"heroicon-o-users\", \"order\": 4, \"title\": \"Socio-Demographic Information\", \"fields\": [{\"id\": \"marital_status\", \"type\": \"select\", \"label\": \"Marital Status\", \"options\": [{\"label\": \"Single\", \"value\": \"single\"}, {\"label\": \"Married\", \"value\": \"married\"}, {\"label\": \"Divorced\", \"value\": \"divorced\"}, {\"label\": \"Separated\", \"value\": \"separated\"}, {\"label\": \"Widowed\", \"value\": \"widowed\"}], \"conditionalDisplay\": {\"ageCondition\": {\"minAge\": 18}}}, {\"id\": \"living_arrangement\", \"type\": \"select\", \"label\": \"Living Arrangement\", \"options\": [{\"label\": \"With Parents\", \"value\": \"parents\"}, {\"label\": \"With Spouse\", \"value\": \"spouse\"}, {\"label\": \"Alone\", \"value\": \"alone\"}, {\"label\": \"With Relative