DROP TABLE IF EXISTS `assessment_form_versions`;
CREATE TABLE `assessment_form_versions` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `form_schema_id` bigint unsigned NOT NULL,
  `version` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `schema_snapshot` json NOT NULL,
  `change_notes` text COLLATE utf8mb4_unicode_ci,
  `created_by` bigint unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `assessment_form_versions_created_by_foreign` (`created_by`),
  KEY `assessment_form_versions_form_schema_id_version_index` (`form_schema_id`,`version`),
  CONSTRAINT `assessment_form_versions_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`),
  CONSTRAINT `assessment_form_versions_form_schema_id_foreign` FOREIGN KEY (`form_schema_id`) REFERENCES `assessment_form_schemas` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `batch_invoice_items`;
CREATE TABLE `batch_invoice_items` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `insurance_batch_invoice_id` bigint unsigned NOT NULL,
  `insurance_claim_id` bigint unsigned NOT NULL,
  `claim_number` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `service_date` date NOT NULL,
  `client_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `client_uci` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `claimed_amount` decimal(10,2) NOT NULL,
  `approved_amount` decimal(10,2) NOT NULL DEFAULT '0.00',
  `paid_amount` decimal(10,2) NOT NULL DEFAULT '0.00',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_batch_items_invoice` (`insurance_batch_invoice_id`),
  KEY `idx_batch_items_claim` (`insurance_claim_id`),
  CONSTRAINT `fk_batch_items_claim` FOREIGN KEY (`insurance_claim_id`) REFERENCES `insurance_claims` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_batch_items_invoice` FOREIGN KEY (`insurance_batch_invoice_id`) REFERENCES `insurance_batch_invoices` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `branches`;
CREATE TABLE `branches` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `code` varchar(10) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Branch code for UCI (e.g., KS, SL, MK)',
  `name` varchar(150) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Branch full name (e.g., Kasarani Branch)',
  `type` enum('main','satellite','outreach') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'main' COMMENT 'Branch type: main (HQ), satellite (permanent), outreach (temporary)',
  `phone` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Primary contact number',
  `email` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Branch email address',
  `address` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Physical address',
  `county_id` bigint unsigned DEFAULT NULL,
  `sub_county_id` bigint unsigned DEFAULT NULL,
  `ward_id` bigint unsigned DEFAULT NULL,
  `latitude` decimal(10,8) DEFAULT NULL COMMENT 'GPS latitude for mapping',
  `longitude` decimal(11,8) DEFAULT NULL COMMENT 'GPS longitude for mapping',
  `is_active` tinyint(1) NOT NULL DEFAULT '1' COMMENT 'Branch operational status',
  `opened_at` date DEFAULT NULL COMMENT 'Branch opening date',
  `closed_at` date DEFAULT NULL COMMENT 'Branch closure date (if applicable)',
  `operating_hours_start` time NOT NULL DEFAULT '08:00:00' COMMENT 'Daily opening time',
  `operating_hours_end` time NOT NULL DEFAULT '17:00:00' COMMENT 'Daily closing time',
  `operating_days` json DEFAULT NULL COMMENT 'Operating days: [1=Monday, 2=Tuesday, etc.]',
  `max_daily_clients` int NOT NULL DEFAULT '100' COMMENT 'Maximum clients per day',
  `current_daily_clients` int NOT NULL DEFAULT '0' COMMENT 'Counter for today''s clients',
  `last_client_reset_date` date DEFAULT NULL COMMENT 'Last date daily counter was reset',
  `manager_id` bigint unsigned DEFAULT NULL,
  `settings` json DEFAULT NULL COMMENT 'Branch-specific settings (JSON)',
  `notes` text COLLATE utf8mb4_unicode_ci COMMENT 'Administrative notes',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT 'Soft delete for historical data preservation',
  PRIMARY KEY (`id`),
  UNIQUE KEY `branches_code_unique` (`code`),
  KEY `branches_manager_id_foreign` (`manager_id`),
  KEY `idx_branches_code` (`code`),
  KEY `idx_branches_type` (`type`),
  KEY `idx_branches_active` (`is_active`),
  KEY `idx_branches_created` (`created_at`),
  KEY `branches_county_id_index` (`county_id`),
  KEY `branches_sub_county_id_index` (`sub_county_id`),
  KEY `branches_ward_id_index` (`ward_id`),
  CONSTRAINT `branches_county_id_foreign` FOREIGN KEY (`county_id`) REFERENCES `counties` (`id`) ON DELETE SET NULL,
  CONSTRAINT `branches_manager_id_foreign` FOREIGN KEY (`manager_id`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `branches_sub_county_id_foreign` FOREIGN KEY (`sub_county_id`) REFERENCES `sub_counties` (`id`) ON DELETE SET NULL,
  CONSTRAINT `branches_ward_id_foreign` FOREIGN KEY (`ward_id`) REFERENCES `wards` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Multi-tenant branch management for KISE centers';

