DROP TABLE IF EXISTS `client_addresses`;
CREATE TABLE `client_addresses` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `client_id` bigint unsigned NOT NULL,
  `type` enum('physical','postal','temporary') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'physical' COMMENT 'Address type',
  `is_primary` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Primary address flag',
  `address_line_1` text COLLATE utf8mb4_unicode_ci COMMENT 'Street address line 1',
  `address_line_2` text COLLATE utf8mb4_unicode_ci COMMENT 'Street address line 2',
  `city` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'City/town',
  `county_id` bigint unsigned DEFAULT NULL,
  `sub_county_id` bigint unsigned DEFAULT NULL,
  `ward_id` bigint unsigned DEFAULT NULL,
  `postal_code` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Postal code',
  `country` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Kenya' COMMENT 'Country',
  `latitude` decimal(10,8) DEFAULT NULL COMMENT 'GPS latitude',
  `longitude` decimal(11,8) DEFAULT NULL COMMENT 'GPS longitude',
  `notes` text COLLATE utf8mb4_unicode_ci COMMENT 'Address notes/directions',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_addresses_client` (`client_id`),
  KEY `idx_addresses_type` (`type`),
  KEY `idx_addresses_primary` (`is_primary`),
  KEY `client_addresses_county_id_index` (`county_id`),
  KEY `client_addresses_sub_county_id_index` (`sub_county_id`),
  KEY `client_addresses_ward_id_index` (`ward_id`),
  CONSTRAINT `client_addresses_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE,
  CONSTRAINT `client_addresses_county_id_foreign` FOREIGN KEY (`county_id`) REFERENCES `counties` (`id`) ON DELETE SET NULL,
  CONSTRAINT `client_addresses_sub_county_id_foreign` FOREIGN KEY (`sub_county_id`) REFERENCES `sub_counties` (`id`) ON DELETE SET NULL,
  CONSTRAINT `client_addresses_ward_id_foreign` FOREIGN KEY (`ward_id`) REFERENCES `wards` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `client_allergies`;
CREATE TABLE `client_allergies` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `client_id` bigint unsigned NOT NULL,
  `allergy_type` enum('drug','food','environmental','insect','latex','other') COLLATE utf8mb4_unicode_ci NOT NULL,
  `allergen_name` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  `typical_reactions` json DEFAULT NULL,
  `reaction` text COLLATE utf8mb4_unicode_ci,
  `severity` enum('mild','moderate','severe','life_threatening') COLLATE utf8mb4_unicode_ci NOT NULL,
  `diagnosed_date` date DEFAULT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `client_allergies_client_id_index` (`client_id`),
  KEY `client_allergies_allergy_type_index` (`allergy_type`),
  KEY `client_allergies_severity_index` (`severity`),
  KEY `client_allergies_is_active_index` (`is_active`),
  CONSTRAINT `client_allergies_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `client_contacts`;
CREATE TABLE `client_contacts` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `client_id` bigint unsigned NOT NULL,
  `contact_type` enum('emergency','guardian','next_of_kin','caregiver') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'emergency',
  `full_name` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  `relationship` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `phone_primary` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `phone_secondary` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `email` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `national_id` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `address` text COLLATE utf8mb4_unicode_ci,
  `is_primary` tinyint(1) NOT NULL DEFAULT '0',
  `notes` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `client_contacts_client_id_index` (`client_id`),
  KEY `client_contacts_contact_type_index` (`contact_type`),
  KEY `client_contacts_is_primary_index` (`is_primary`),
  CONSTRAINT `client_contacts_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `client_credit_accounts`;
CREATE TABLE `client_credit_accounts` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `client_id` bigint unsigned NOT NULL,
  `branch_id` bigint unsigned NOT NULL,
  `account_number` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `credit_limit` decimal(10,2) NOT NULL DEFAULT '0.00',
  `current_balance` decimal(10,2) NOT NULL DEFAULT '0.00',
  `available_credit` decimal(10,2) NOT NULL DEFAULT '0.00',
  `status` enum('active','suspended','closed') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active',
  `notes` text COLLATE utf8mb4_unicode_ci,
  `created_by` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `client_credit_accounts_account_number_unique` (`account_number`),
  KEY `client_credit_accounts_branch_id_foreign` (`branch_id`),
  KEY `client_credit_accounts_created_by_foreign` (`created_by`),
  KEY `client_credit_accounts_client_id_branch_id_index` (`client_id`,`branch_id`),
  KEY `idx_ca_client_status_balance` (`client_id`,`status`,`current_balance`),
  CONSTRAINT `client_credit_accounts_branch_id_foreign` FOREIGN KEY (`branch_id`) REFERENCES `branches` (`id`) ON DELETE CASCADE,
  CONSTRAINT `client_credit_accounts_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE,
  CONSTRAINT `client_credit_accounts_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `client_credit_accounts` (`id`, `client_id`, `branch_id`, `account_number`, `credit_limit`, `current_balance`, `available_credit`, `status`, `notes`, `created_by`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1,	1,	1,	'CRD-20260127-00001',	50000.00,	5000.00,	45000.00,	'active',	'Test credit account',	1,	'2026-01-27 20:35:58',	'2026-01-27 20:35:58',	NULL),
(2,	2,	1,	'CRD-20260127-00002',	30000.00,	0.00,	30000.00,	'active',	'Test credit account 2',	1,	'2026-01-27 20:35:58',	'2026-01-27 20:35:58',	NULL);

DELIMITER ;;

CREATE TRIGGER `trg_credit_account_before_insert` BEFORE INSERT ON `client_credit_accounts` FOR EACH ROW
BEGIN
    -- Auto-calculate available credit
    SET NEW.available_credit = NEW.credit_limit - NEW.current_balance;
    
    -- Auto-generate account number if not provided
    IF NEW.account_number IS NULL OR NEW.account_number = '' THEN
        SET NEW.account_number = CONCAT('CRD-', DATE_FORMAT(NOW(), '%Y%m%d'), '-', LPAD((
            SELECT COALESCE(MAX(CAST(SUBSTRING(account_number, -5) AS UNSIGNED)), 0) + 1 
            FROM client_credit_accounts 
            WHERE account_number LIKE CONCAT('CRD-', DATE_FORMAT(NOW(), '%Y%m%d'), '-%')
        ), 5, '0'));
    END IF;
END;;

CREATE TRIGGER `trg_credit_account_before_update` BEFORE UPDATE ON `client_credit_accounts` FOR EACH ROW
BEGIN
    -- Auto-calculate available credit on update
    SET NEW.available_credit = NEW.credit_limit - NEW.current_balance;
END;;

DELIMITER ;

DROP TABLE IF EXISTS `client_disabilities`;
CREATE TABLE `client_disabilities` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `client_id` bigint unsigned NOT NULL,
  `is_disability_known` tinyint(1) NOT NULL DEFAULT '0',
  `disability_categories` json DEFAULT NULL,
  `onset` enum('congenital','acquired','unknown') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `level_of_functioning` enum('mild','moderate','severe','profound') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `assistive_technology` json DEFAULT NULL,
  `assistive_technology_notes` text COLLATE utf8mb4_unicode_ci,
  `disability_notes` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `client_disabilities_client_id_index` (`client_id`),
  KEY `client_disabilities_is_disability_known_index` (`is_disability_known`),
  KEY `client_disabilities_level_of_functioning_index` (`level_of_functioning`),
  CONSTRAINT `client_disabilities_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `client_documents`;
CREATE TABLE `client_documents` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `client_id` bigint unsigned NOT NULL,
  `document_type` enum('birth_certificate','national_id','passport','medical_report','assessment_report','referral_letter','other') COLLATE utf8mb4_unicode_ci NOT NULL,
  `title` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  `file_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `file_path` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL,
