DROP TABLE IF EXISTS `clients`;
CREATE TABLE `clients` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `branch_id` bigint unsigned NOT NULL,
  `uci` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Unique Client Identifier (e.g., KS-2024-00001)',
  `first_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Client first name',
  `middle_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Client middle name',
  `last_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Client last name',
  `date_of_birth` date NOT NULL COMMENT 'Date of birth',
  `estimated_age` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `gender` enum('male','female','intersex','prefer_not_to_say') COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Client gender',
  `phone_primary` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Primary phone number',
  `phone_secondary` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Secondary phone number',
  `email` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Email address',
  `preferred_communication` enum('sms','phone','email') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'sms',
  `consent_to_sms` tinyint(1) NOT NULL DEFAULT '0',
  `national_id` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'National ID number',
  `birth_certificate_number` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Birth certificate number',
  `passport_number` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Passport number',
  `nhif_number` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'NHIF number',
  `sha_number` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'SHA (Social Health Authority) number',
  `ncpwd_number` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'NCPWD registration number',
  `guardian_name` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Guardian/parent full name',
  `guardian_relationship` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Relationship to client',
  `guardian_phone` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Guardian phone number',
  `guardian_national_id` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Guardian national ID',
  `county_id` bigint unsigned DEFAULT NULL,
  `sub_county_id` bigint unsigned DEFAULT NULL,
  `ward_id` bigint unsigned DEFAULT NULL,
  `village` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Village/estate',
  `primary_address` text COLLATE utf8mb4_unicode_ci,
  `landmark` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `blood_group` enum('A+','A-','B+','B-','AB+','AB-','O+','O-','unknown') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'unknown' COMMENT 'Blood group',
  `medical_notes` text COLLATE utf8mb4_unicode_ci COMMENT 'Important medical notes',
  `client_type` enum('new','returning','old_new') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'new' COMMENT 'Client registration type',
  `first_visit_date` date DEFAULT NULL COMMENT 'Date of first visit',
  `referral_source` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'How client found KISE',
  `is_active` tinyint(1) NOT NULL DEFAULT '1' COMMENT 'Client account active status',
  `deactivation_reason` text COLLATE utf8mb4_unicode_ci COMMENT 'Reason if deactivated',
  `photo_path` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Profile photo storage path',
  `metadata` json DEFAULT NULL COMMENT 'Additional flexible data',
  `notes` text COLLATE utf8mb4_unicode_ci COMMENT 'Administrative notes',
  `registered_by` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `last_visit_date` date DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `registration_date` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `clients_uci_unique` (`uci`),
  UNIQUE KEY `clients_national_id_unique` (`national_id`),
  KEY `clients_registered_by_foreign` (`registered_by`),
  KEY `idx_clients_branch` (`branch_id`),
  KEY `idx_clients_uci` (`uci`),
  KEY `idx_clients_name` (`first_name`,`last_name`),
  KEY `idx_clients_dob` (`date_of_birth`),
  KEY `idx_clients_phone` (`phone_primary`),
  KEY `idx_clients_national_id` (`national_id`),
  KEY `idx_clients_type` (`client_type`),
  KEY `idx_clients_active` (`is_active`),
  KEY `idx_clients_created` (`created_at`),
  KEY `clients_preferred_communication_index` (`preferred_communication`),
  KEY `clients_consent_to_sms_index` (`consent_to_sms`),
  KEY `clients_county_id_index` (`county_id`),
  KEY `clients_sub_county_id_index` (`sub_county_id`),
  KEY `clients_ward_id_index` (`ward_id`),
  CONSTRAINT `clients_branch_id_foreign` FOREIGN KEY (`branch_id`) REFERENCES `branches` (`id`) ON DELETE CASCADE,
  CONSTRAINT `clients_county_id_foreign` FOREIGN KEY (`county_id`) REFERENCES `counties` (`id`) ON DELETE SET NULL,
  CONSTRAINT `clients_registered_by_foreign` FOREIGN KEY (`registered_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `clients_sub_county_id_foreign` FOREIGN KEY (`sub_county_id`) REFERENCES `sub_counties` (`id`) ON DELETE SET NULL,
  CONSTRAINT `clients_ward_id_foreign` FOREIGN KEY (`ward_id`) REFERENCES `wards` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

