DROP TABLE IF EXISTS `credit_transactions`;
CREATE TABLE `credit_transactions` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `credit_account_id` bigint unsigned NOT NULL,
  `invoice_id` bigint unsigned DEFAULT NULL,
  `payment_id` bigint unsigned DEFAULT NULL,
  `transaction_number` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `type` enum('charge','payment','adjustment','refund') COLLATE utf8mb4_unicode_ci NOT NULL,
  `amount` decimal(10,2) NOT NULL,
  `balance_before` decimal(10,2) NOT NULL,
  `balance_after` decimal(10,2) NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `processed_by` bigint unsigned NOT NULL,
  `transaction_date` timestamp NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `credit_transactions_transaction_number_unique` (`transaction_number`),
  KEY `credit_transactions_invoice_id_foreign` (`invoice_id`),
  KEY `credit_transactions_payment_id_foreign` (`payment_id`),
  KEY `credit_transactions_processed_by_foreign` (`processed_by`),
  KEY `credit_transactions_credit_account_id_transaction_date_index` (`credit_account_id`,`transaction_date`),
  KEY `idx_ct_account_type_date` (`credit_account_id`,`type`,`transaction_date`),
  CONSTRAINT `credit_transactions_credit_account_id_foreign` FOREIGN KEY (`credit_account_id`) REFERENCES `client_credit_accounts` (`id`) ON DELETE CASCADE,
  CONSTRAINT `credit_transactions_invoice_id_foreign` FOREIGN KEY (`invoice_id`) REFERENCES `invoices` (`id`) ON DELETE SET NULL,
  CONSTRAINT `credit_transactions_payment_id_foreign` FOREIGN KEY (`payment_id`) REFERENCES `payments` (`id`) ON DELETE SET NULL,
  CONSTRAINT `credit_transactions_processed_by_foreign` FOREIGN KEY (`processed_by`) REFERENCES `users` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `credit_transactions` (`id`, `credit_account_id`, `invoice_id`, `payment_id`, `transaction_number`, `type`, `amount`, `balance_before`, `balance_after`, `description`, `notes`, `processed_by`, `transaction_date`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1,	1,	NULL,	NULL,	'CRT-20260127-00001',	'charge',	5000.00,	0.00,	5000.00,	'Initial credit charge for testing',	NULL,	1,	'2026-01-27 20:35:58',	'2026-01-27 20:35:58',	'2026-01-27 20:35:58',	NULL);

DELIMITER ;;

CREATE TRIGGER `trg_credit_transaction_before_insert` BEFORE INSERT ON `credit_transactions` FOR EACH ROW
BEGIN
    -- Auto-generate transaction number if not provided
    IF NEW.transaction_number IS NULL OR NEW.transaction_number = '' THEN
        SET NEW.transaction_number = CONCAT('CRT-', DATE_FORMAT(NOW(), '%Y%m%d'), '-', LPAD((
            SELECT COALESCE(MAX(CAST(SUBSTRING(transaction_number, -5) AS UNSIGNED)), 0) + 1 
            FROM credit_transactions 
            WHERE transaction_number LIKE CONCAT('CRT-', DATE_FORMAT(NOW(), '%Y%m%d'), '-%')
        ), 5, '0'));
    END IF;
END;;

DELIMITER ;

DROP TABLE IF EXISTS `crisis_incidents`;
CREATE TABLE `crisis_incidents` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `incident_number` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `visit_id` bigint unsigned DEFAULT NULL,
  `client_id` bigint unsigned NOT NULL,
  `branch_id` bigint unsigned NOT NULL,
  `incident_type` enum('behavioral','medical','safety','environmental','other') COLLATE utf8mb4_unicode_ci NOT NULL,
  `severity` enum('low','medium','high','critical') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'medium',
  `occurred_at` timestamp NOT NULL,
  `location` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `trigger_factors` text COLLATE utf8mb4_unicode_ci,
  `immediate_actions_taken` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `interventions_applied` text COLLATE utf8mb4_unicode_ci,
  `client_response` text COLLATE utf8mb4_unicode_ci,
  `injury_occurred` tinyint(1) NOT NULL DEFAULT '0',
  `injury_details` text COLLATE utf8mb4_unicode_ci,
  `emergency_services_called` tinyint(1) NOT NULL DEFAULT '0',
  `emergency_services_details` text COLLATE utf8mb4_unicode_ci,
  `family_notified` tinyint(1) NOT NULL DEFAULT '0',
  `family_notified_at` timestamp NULL DEFAULT NULL,
  `follow_up_required` text COLLATE utf8mb4_unicode_ci,
  `status` enum('active','under_review','resolved','escalated') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active',
  `reported_by` bigint unsigned NOT NULL,
  `reported_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `witnesses` json DEFAULT NULL,
  `resolved_by` bigint unsigned DEFAULT NULL,
  `resolved_at` timestamp NULL DEFAULT NULL,
  `resolution_notes` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `crisis_incidents_incident_number_unique` (`incident_number`),
  KEY `crisis_incidents_visit_id_foreign` (`visit_id`),
  KEY `crisis_incidents_reported_by_foreign` (`reported_by`),
  KEY `crisis_incidents_resolved_by_foreign` (`resolved_by`),
  KEY `crisis_incidents_incident_number_index` (`incident_number`),
  KEY `crisis_incidents_client_id_index` (`client_id`),
  KEY `crisis_incidents_branch_id_index` (`branch_id`),
  KEY `crisis_incidents_incident_type_index` (`incident_type`),
  KEY `crisis_incidents_severity_index` (`severity`),
  KEY `crisis_incidents_status_index` (`status`),
  KEY `crisis_incidents_occurred_at_index` (`occurred_at`),
  CONSTRAINT `crisis_incidents_branch_id_foreign` FOREIGN KEY (`branch_id`) REFERENCES `branches` (`id`) ON DELETE CASCADE,
  CONSTRAINT `crisis_incidents_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE,
  CONSTRAINT `crisis_incidents_reported_by_foreign` FOREIGN KEY (`reported_by`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `crisis_incidents_resolved_by_foreign` FOREIGN KEY (`resolved_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `crisis_incidents_visit_id_foreign` FOREIGN KEY (`visit_id`) REFERENCES `visits` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `data_sync_logs`;
CREATE TABLE `data_sync_logs` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `source_branch_id` bigint unsigned NOT NULL,
  `target_branch_id` bigint unsigned DEFAULT NULL,
  `sync_type` enum('outreach_to_main','main_to_outreach','branch_to_branch','backup') COLLATE utf8mb4_unicode_ci NOT NULL,
  `data_type` enum('clients','visits','services','invoices','all') COLLATE utf8mb4_unicode_ci NOT NULL,
  `sync_started_at` timestamp NOT NULL,
  `sync_completed_at` timestamp NULL DEFAULT NULL,
  `status` enum('pending','in_progress','completed','failed','partial') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `records_total` int NOT NULL DEFAULT '0',
  `records_synced` int NOT NULL DEFAULT '0',
  `records_failed` int NOT NULL DEFAULT '0',
  `sync_summary` json DEFAULT NULL,
  `error_message` text COLLATE utf8mb4_unicode_ci,
  `error_details` json DEFAULT NULL,
  `initiated_by` bigint unsigned NOT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `data_sync_logs_initiated_by_foreign` (`initiated_by`),
  KEY `data_sync_logs_source_branch_id_index` (`source_branch_id`),
  KEY `data_sync_logs_target_branch_id_index` (`target_branch_id`),
  KEY `data_sync_logs_sync_type_index` (`sync_type`),
  KEY `data_sync_logs_status_index` (`status`),
  KEY `data_sync_logs_sync_started_at_index` (`sync_started_at`),
  CONSTRAINT `data_sync_logs_initiated_by_foreign` FOREIGN KEY (`initiated_by`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `data_sync_logs_source_branch_id_foreign` FOREIGN KEY (`source_branch_id`) REFERENCES `branches` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `data_sync_logs_target_branch_id_foreign` FOREIGN KEY (`target_branch_id`) REFERENCES `branches` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `departments`;
CREATE TABLE `departments` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `branch_id` bigint unsigned NOT NULL,
  `code` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Department code (e.g., PHYS, OT, SLT)',
  `name` varchar(150) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Department name',
  `description` text COLLATE utf8mb4_unicode_ci COMMENT 'Department description',
  `has_queue` tinyint(1) NOT NULL DEFAULT '1' COMMENT 'Does this department use a queue?',
  `queue_capacity` int NOT NULL DEFAULT '50' COMMENT 'Maximum queue size',
  `sla_target_minutes` int NOT NULL DEFAULT '30' COMMENT 'Service level agreement (minutes)',
  `location` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Room/Building location',
  `phone` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Department phone',
  `email` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Department email',
  `head_of_department_id` bigint unsigned DEFAULT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT '1' COMMENT 'Department operational status',
  `settings` json DEFAULT NULL COMMENT 'Department-specific settings',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_dept_code_per_branch` (`branch_id`,`code`),
  KEY `departments_head_of_department_id_foreign` (`head_of_department_id`),
  KEY `idx_departments_branch` (`branch_id`),
  KEY `idx_departments_active` (`is_active`),
  KEY `idx_departments_queue` (`has_queue`),
  CONSTRAINT `departments_branch_id_foreign` FOREIGN KEY (`branch_id`) REFERENCES `branches` (`id`) ON DELETE CASCADE,
  CONSTRAINT `departments_head_of_department_id_foreign` FOREIGN KEY (`head_of_department_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

