DROP TABLE IF EXISTS `external_referrals`;
CREATE TABLE `external_referrals` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `visit_id` bigint unsigned NOT NULL,
  `client_id` bigint unsigned NOT NULL,
  `referring_provider_id` bigint unsigned NOT NULL,
  `from_department_id` bigint unsigned NOT NULL,
  `facility_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `facility_type` enum('hospital','specialist_clinic','diagnostic_center','rehabilitation_center','other') COLLATE utf8mb4_unicode_ci NOT NULL,
  `department_specialty` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'e.g., Pediatric Ophthalmology, Neurology',
  `facility_contact` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `facility_email` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `urgency` enum('routine','urgent','emergency') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'routine',
  `status` enum('sent','appointment_scheduled','attended','completed','cancelled','lost_to_follow_up') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'sent',
  `reason` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Main reason for referral',
  `clinical_summary` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Brief clinical summary',
  `investigations_done` text COLLATE utf8mb4_unicode_ci COMMENT 'Tests/assessments completed at KISE',
  `current_management` text COLLATE utf8mb4_unicode_ci COMMENT 'Current treatment/interventions',
  `specific_request` text COLLATE utf8mb4_unicode_ci COMMENT 'What is specifically requested from specialist',
  `preferred_contact` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Client/guardian preferred contact',
  `alternative_contact` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `referral_letter_path` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Path to generated referral letter PDF',
  `supporting_documents` json DEFAULT NULL COMMENT 'Array of document paths',
  `appointment_date` date DEFAULT NULL,
  `appointment_time` time DEFAULT NULL,
  `feedback` text COLLATE utf8mb4_unicode_ci COMMENT 'Feedback from receiving facility',
  `feedback_documents` json DEFAULT NULL COMMENT 'Reports/letters from facility',
  `referred_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `appointment_confirmed_at` timestamp NULL DEFAULT NULL,
  `attended_at` timestamp NULL DEFAULT NULL,
  `feedback_received_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `external_referrals_visit_id_foreign` (`visit_id`),
  KEY `external_referrals_referring_provider_id_foreign` (`referring_provider_id`),
  KEY `external_referrals_from_department_id_foreign` (`from_department_id`),
  KEY `external_referrals_client_id_status_index` (`client_id`,`status`),
  KEY `external_referrals_status_index` (`status`),
  KEY `external_referrals_appointment_date_index` (`appointment_date`),
  CONSTRAINT `external_referrals_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE,
  CONSTRAINT `external_referrals_from_department_id_foreign` FOREIGN KEY (`from_department_id`) REFERENCES `departments` (`id`),
  CONSTRAINT `external_referrals_referring_provider_id_foreign` FOREIGN KEY (`referring_provider_id`) REFERENCES `users` (`id`),
  CONSTRAINT `external_referrals_visit_id_foreign` FOREIGN KEY (`visit_id`) REFERENCES `visits` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `failed_jobs`;
CREATE TABLE `failed_jobs` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `uuid` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `connection` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `queue` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `payload` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `exception` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `failed_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `failed_jobs_uuid_unique` (`uuid`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `functional_screenings`;
CREATE TABLE `functional_screenings` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `intake_assessment_id` bigint unsigned NOT NULL,
  `client_id` bigint unsigned NOT NULL,
  `mobility_score` int DEFAULT NULL,
  `self_care_score` int DEFAULT NULL,
  `communication_score` int DEFAULT NULL,
  `cognition_score` int DEFAULT NULL,
  `social_interaction_score` int DEFAULT NULL,
  `emotional_regulation_score` int DEFAULT NULL,
  `sensory_processing_score` int DEFAULT NULL,
