DROP TABLE IF EXISTS `insurance_batch_invoices`;
CREATE TABLE `insurance_batch_invoices` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `batch_number` varchar(50) NOT NULL COMMENT 'BATCH-SHA-202601-001',
  `sponsor_type` enum('sha','ncpwd','insurance_private') NOT NULL,
  `insurance_provider_id` bigint unsigned DEFAULT NULL,
  `insurance_provider_name` varchar(255) DEFAULT NULL,
  `period_start` date NOT NULL,
  `period_end` date NOT NULL,
  `period_label` varchar(50) DEFAULT NULL COMMENT 'e.g., January 2026, Week 3',
