DELIMITER ;;

CREATE TRIGGER `trg_update_batch_totals_after_claim_insert` AFTER INSERT ON `insurance_claims` FOR EACH ROW
BEGIN
    IF NEW.insurance_batch_invoice_id IS NOT NULL THEN
        UPDATE insurance_batch_invoices
        SET 
            total_claims = (
                SELECT COUNT(*) 
                FROM insurance_claims 
                WHERE insurance_batch_invoice_id = NEW.insurance_batch_invoice_id
            ),
            total_amount = (
                SELECT COALESCE(SUM(claim_amount), 0) 
                FROM insurance_claims 
                WHERE insurance_batch_invoice_id = NEW.insurance_batch_invoice_id
            ),
            approved_amount = (
                SELECT COALESCE(SUM(approved_amount), 0) 
                FROM insurance_claims 
                WHERE insurance_batch_invoice_id = NEW.insurance_batch_invoice_id
            ),
            paid_amount = (
                SELECT COALESCE(SUM(paid_amount), 0) 
                FROM insurance_claims 
                WHERE insurance_batch_invoice_id = NEW.insurance_batch_invoice_id
            )
        WHERE id = NEW.insurance_batch_invoice_id;
    END IF;
END;;

DELIMITER ;

