CREATE TABLE `invoice_items` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `invoice_id` bigint unsigned DEFAULT NULL,
  `service_booking_id` bigint unsigned DEFAULT NULL,
  `service_id` bigint unsigned DEFAULT NULL,
  `department_id` bigint unsigned DEFAULT NULL,
  `insurance_provider_id` bigint unsigned DEFAULT NULL,
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `quantity` int DEFAULT '1',
  `discount` decimal(10,2) DEFAULT '0.00',
  `unit_price` decimal(10,2) DEFAULT NULL,
  `insurance_covered_amount` decimal(10,2) DEFAULT '0.00',
  `client_copay_amount` decimal(10,2) DEFAULT '0.00',
  `subtotal` decimal(10,2) DEFAULT NULL,
  `discount_amount` decimal(10,2) DEFAULT '0.00',
  `covered_amount` decimal(10,2) DEFAULT '0.00',
  `total` decimal(10,2) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `sponsor_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'sha, ncpwd, insurance_private, waiver',
  `sponsor_percentage` decimal(5,2) DEFAULT NULL COMMENT 'Actual sponsor percentage applied',
  `sponsor_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT 'Amount sponsor will pay',
  `client_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT 'Amount client must pay',
  `client_payment_status` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'unpaid',
  `sponsor_claim_status` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  PRIMARY KEY (`id`),
  KEY `invoice_items_invoice_id_index` (`invoice_id`),
  KEY `invoice_items_service_booking_id_index` (`service_booking_id`),
  KEY `invoice_items_service_id_index` (`service_id`),
  KEY `invoice_items_department_id_index` (`department_id`),
  KEY `invoice_items_insurance_provider_id_foreign` (`insurance_provider_id`),
  KEY `idx_invoice_items_sponsor_type` (`sponsor_type`),
  KEY `idx_invoice_items_claim_status` (`sponsor_claim_status`),
  CONSTRAINT `invoice_items_department_id_foreign` FOREIGN KEY (`department_id`) REFERENCES `departments` (`id`) ON DELETE CASCADE,
  CONSTRAINT `invoice_items_insurance_provider_id_foreign` FOREIGN KEY (`insurance_provider_id`) REFERENCES `insurance_providers` (`id`),
  CONSTRAINT `invoice_items_invoice_id_foreign` FOREIGN KEY (`invoice_id`) REFERENCES `invoices` (`id`) ON DELETE CASCADE,
  CONSTRAINT `invoice_items_service_booking_id_foreign` FOREIGN KEY (`service_booking_id`) REFERENCES `service_bookings` (`id`) ON DELETE SET NULL,
  CONSTRAINT `invoice_items_service_id_foreign` FOREIGN KEY (`service_id`) REFERENCES `services` (`id`) ON DELETE RESTRICT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

