DROP TABLE IF EXISTS `invoices`;
CREATE TABLE `invoices` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `invoice_number` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `visit_id` bigint unsigned DEFAULT NULL,
  `client_id` bigint unsigned DEFAULT NULL,
  `branch_id` bigint unsigned DEFAULT NULL,
  `subtotal` decimal(10,2) DEFAULT '0.00',
  `covered_amount` decimal(10,2) DEFAULT '0.00',
  `discount_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `discount_value` decimal(10,2) DEFAULT '0.00',
  `discount_amount` decimal(10,2) DEFAULT '0.00',
  `discount_reason` text COLLATE utf8mb4_unicode_ci,
  `discount_approved_by` bigint unsigned DEFAULT NULL,
  `tax_amount` decimal(10,2) DEFAULT '0.00',
  `final_amount` decimal(10,2) DEFAULT NULL,
  `total_amount` decimal(10,2) DEFAULT '0.00',
  `amount_paid` decimal(10,2) DEFAULT '0.00',
  `balance_due` decimal(10,2) DEFAULT '0.00',
  `status` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `payment_pathway` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `payment_method` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `insurance_provider_id` bigint unsigned DEFAULT NULL,
  `approved_at` timestamp NULL DEFAULT NULL,
  `verified_at` timestamp NULL DEFAULT NULL,
  `rejected_at` timestamp NULL DEFAULT NULL,
  `approved_by` bigint unsigned DEFAULT NULL,
  `paid_at` timestamp NULL DEFAULT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `approval_notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `rejection_reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `verification_notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `payment_notes` text COLLATE utf8mb4_unicode_ci,
  `generated_by` bigint unsigned DEFAULT NULL,
  `payment_administrator_id` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `payment_date` datetime DEFAULT NULL,
  `due_date` datetime DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `verification_status` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `waiver_approval_status` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `paid_by` bigint unsigned DEFAULT NULL,
  `issued_at` datetime DEFAULT NULL,
  `total_client_amount` decimal(10,2) DEFAULT '0.00' COMMENT 'Total client must pay (sum of all items client_amount)',
  `total_sponsor_amount` decimal(10,2) DEFAULT '0.00' COMMENT 'Total sponsor will pay (sum of all items sponsor_amount)',
  `client_payment_status` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'unpaid',
  `sponsor_claim_status` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `has_sponsor` tinyint(1) DEFAULT '0' COMMENT 'Whether invoice has insurance/sponsor component',
  `issued_by` tinyint(1) DEFAULT NULL,
  `verified_by` tinyint(1) DEFAULT NULL,
  `rejected_by` tinyint(1) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `invoices_invoice_number_unique` (`invoice_number`),
  KEY `invoices_discount_approved_by_foreign` (`discount_approved_by`),
  KEY `invoices_approved_by_foreign` (`approved_by`),
  KEY `invoices_generated_by_foreign` (`generated_by`),
  KEY `invoices_invoice_number_index` (`invoice_number`),
  KEY `invoices_visit_id_index` (`visit_id`),
  KEY `invoices_client_id_index` (`client_id`),
  KEY `invoices_branch_id_index` (`branch_id`),
  KEY `invoices_status_index` (`status`),
  KEY `invoices_payment_pathway_index` (`payment_pathway`),
  KEY `invoices_payment_administrator_id_foreign` (`payment_administrator_id`),
  KEY `invoices_insurance_provider_id_foreign` (`insurance_provider_id`),
  KEY `invoices_verification_status_index` (`verification_status`),
  KEY `invoices_waiver_approval_status_index` (`waiver_approval_status`),
  KEY `idx_invoices_has_sponsor` (`has_sponsor`),
  KEY `idx_invoices_sponsor_claim_status` (`sponsor_claim_status`),
  CONSTRAINT `invoices_approved_by_foreign` FOREIGN KEY (`approved_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `invoices_branch_id_foreign` FOREIGN KEY (`branch_id`) REFERENCES `branches` (`id`) ON DELETE CASCADE,
  CONSTRAINT `invoices_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE,
  CONSTRAINT `invoices_discount_approved_by_foreign` FOREIGN KEY (`discount_approved_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `invoices_generated_by_foreign` FOREIGN KEY (`generated_by`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `invoices_insurance_provider_id_foreign` FOREIGN KEY (`insurance_provider_id`) REFERENCES `insurance_providers` (`id`),
  CONSTRAINT `invoices_payment_administrator_id_foreign` FOREIGN KEY (`payment_administrator_id`) REFERENCES `users` (`id`),
  CONSTRAINT `invoices_visit_id_foreign` FOREIGN KEY (`visit_id`) REFERENCES `visits` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

