DROP TABLE IF EXISTS `queue_entries`;
CREATE TABLE `queue_entries` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `queue_id` bigint unsigned DEFAULT NULL,
  `visit_id` bigint unsigned DEFAULT NULL,
  `branch_id` bigint unsigned DEFAULT NULL,
  `client_id` bigint unsigned DEFAULT NULL,
  `service_booking_id` bigint unsigned DEFAULT NULL,
  `service_provider_id` bigint unsigned DEFAULT NULL,
  `service_id` bigint unsigned NOT NULL,
  `department_id` bigint unsigned NOT NULL,
  `estimated_duration` int DEFAULT NULL COMMENT 'Duration in minutes',
  `queue_number` int NOT NULL,
  `position` int DEFAULT NULL,
  `priority` enum('low','normal','high','urgent') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'normal',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'waiting',
  `priority_level` enum('critical','urgent','high','normal','low') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'normal' COMMENT 'Set from triage risk assessment',
  `arrived_at` timestamp NULL DEFAULT NULL,
  `waiting_started_at` timestamp NULL DEFAULT NULL,
  `verified_at` datetime DEFAULT NULL,
  `service_started_at` timestamp NULL DEFAULT NULL,
  `service_completed_at` timestamp NULL DEFAULT NULL,
  `joined_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `called_at` timestamp NULL DEFAULT NULL,
  `called_by` bigint unsigned DEFAULT NULL,
  `verified_by` bigint unsigned DEFAULT NULL,
  `serving_started_at` timestamp NULL DEFAULT NULL,
  `served_by` bigint unsigned DEFAULT NULL,
  `no_show` tinyint(1) NOT NULL DEFAULT '0',
  `completed_at` timestamp NULL DEFAULT NULL,
  `wait_time_minutes` int DEFAULT NULL,
  `service_time_minutes` int DEFAULT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `queue_entries_service_booking_id_foreign` (`service_booking_id`),
  KEY `queue_entries_called_by_foreign` (`called_by`),
  KEY `queue_entries_served_by_foreign` (`served_by`),
  KEY `queue_entries_queue_id_index` (`queue_id`),
  KEY `queue_entries_visit_id_index` (`visit_id`),
  KEY `queue_entries_client_id_index` (`client_id`),
  KEY `queue_entries_queue_number_index` (`queue_number`),
  KEY `queue_entries_status_index` (`status`),
  KEY `queue_entries_priority_index` (`priority`),
  KEY `queue_entries_joined_at_index` (`joined_at`),
  KEY `queue_entries_service_id_index` (`service_id`),
  KEY `queue_entries_department_id_index` (`department_id`),
  KEY `queue_entries_queue_id_status_index` (`queue_id`,`status`),
  KEY `queue_entries_arrived_at_priority_level_position_index` (`arrived_at`,`priority_level`,`position`),
  CONSTRAINT `queue_entries_called_by_foreign` FOREIGN KEY (`called_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `queue_entries_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE,
  CONSTRAINT `queue_entries_department_id_foreign` FOREIGN KEY (`department_id`) REFERENCES `departments` (`id`) ON DELETE CASCADE,
  CONSTRAINT `queue_entries_queue_id_foreign` FOREIGN KEY (`queue_id`) REFERENCES `queues` (`id`) ON DELETE CASCADE,
  CONSTRAINT `queue_entries_served_by_foreign` FOREIGN KEY (`served_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `queue_entries_service_booking_id_foreign` FOREIGN KEY (`service_booking_id`) REFERENCES `service_bookings` (`id`) ON DELETE SET NULL,
  CONSTRAINT `queue_entries_service_id_foreign` FOREIGN KEY (`service_id`) REFERENCES `services` (`id`) ON DELETE CASCADE,
  CONSTRAINT `queue_entries_visit_id_foreign` FOREIGN KEY (`visit_id`) REFERENCES `visits` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

