DROP TABLE IF EXISTS `queue_history`;
CREATE TABLE `queue_history` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `queue_id` bigint unsigned NOT NULL,
  `visit_id` bigint unsigned NOT NULL,
  `client_id` bigint unsigned NOT NULL,
  `queue_number` int NOT NULL,
  `position` int DEFAULT NULL,
  `priority` enum('low','normal','high','urgent') COLLATE utf8mb4_unicode_ci NOT NULL,
  `final_status` enum('completed','no_show','deferred') COLLATE utf8mb4_unicode_ci NOT NULL,
  `joined_at` timestamp NOT NULL,
  `called_at` timestamp NULL DEFAULT NULL,
  `serving_started_at` timestamp NULL DEFAULT NULL,
  `completed_at` timestamp NULL DEFAULT NULL,
  `wait_time_minutes` int DEFAULT NULL,
  `service_time_minutes` int DEFAULT NULL,
  `served_by` bigint unsigned DEFAULT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `archived_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `queue_history_served_by_foreign` (`served_by`),
  KEY `queue_history_queue_id_index` (`queue_id`),
  KEY `queue_history_visit_id_index` (`visit_id`),
  KEY `queue_history_client_id_index` (`client_id`),
  KEY `queue_history_final_status_index` (`final_status`),
  KEY `queue_history_archived_at_index` (`archived_at`),
  CONSTRAINT `queue_history_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE,
  CONSTRAINT `queue_history_queue_id_foreign` FOREIGN KEY (`queue_id`) REFERENCES `queues` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `queue_history_served_by_foreign` FOREIGN KEY (`served_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `queue_history_visit_id_foreign` FOREIGN KEY (`visit_id`) REFERENCES `visits` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `queues`;
CREATE TABLE `queues` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `branch_id` bigint unsigned DEFAULT NULL,
  `visit_id` bigint unsigned DEFAULT NULL,
  `department_id` bigint unsigned DEFAULT NULL,
  `queue_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `queue_display_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `queue_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `max_capacity` int DEFAULT '50',
  `current_count` int DEFAULT '0',
  `current_number` int DEFAULT NULL,
  `sla_target_minutes` int DEFAULT '30',
  `is_active` tinyint(1) DEFAULT '1',
  `active_date` date NOT NULL DEFAULT (curdate()),
  `settings` json DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `queues_queue_code_unique` (`queue_code`),
  KEY `queues_branch_id_index` (`branch_id`),
  KEY `queues_department_id_index` (`department_id`),
  KEY `queues_queue_code_index` (`queue_code`),
  KEY `queues_is_active_index` (`is_active`),
  KEY `queues_active_date_index` (`active_date`),
  KEY `visit_id` (`visit_id`),
  CONSTRAINT `queues_branch_id_foreign` FOREIGN KEY (`branch_id`) REFERENCES `branches` (`id`) ON DELETE CASCADE,
  CONSTRAINT `queues_department_id_foreign` FOREIGN KEY (`department_id`) REFERENCES `departments` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `queues_ibfk_1` FOREIGN KEY (`visit_id`) REFERENCES `visits` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

