DROP TABLE IF EXISTS `school_placements`;
CREATE TABLE `school_placements` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `client_id` bigint unsigned NOT NULL,
  `school_id` bigint unsigned NOT NULL,
  `placement_type` enum('special_school','integrated_program','inclusive_education','home_schooling') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'special_school',
  `program` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Specific program: Vision Impairment Support, etc.',
  `grade_level` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `admission_date` date NOT NULL,
  `expected_completion_date` date DEFAULT NULL,
  `status` enum('pending','active','completed','transferred','discontinued','graduated') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `support_services` json DEFAULT NULL COMMENT 'Array of support services provided',
  `academic_performance` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Latest academic performance: excellent, good, fair, poor',
  `social_performance` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Social integration: excellent, good, fair, poor',
  `special_needs` text COLLATE utf8mb4_unicode_ci COMMENT 'Specific accommodations/modifications needed',
  `last_review_date` date DEFAULT NULL,
  `review_notes` text COLLATE utf8mb4_unicode_ci,
  `placement_officer_id` bigint unsigned DEFAULT NULL,
  `assessment_summary` text COLLATE utf8mb4_unicode_ci COMMENT 'Summary of assessments that led to placement',
  `placement_letter_path` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Path to placement letter PDF',
  `end_date` date DEFAULT NULL,
  `exit_reason` enum('completed','transferred','discontinued','graduated','other') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `exit_notes` text COLLATE utf8mb4_unicode_ci,
  `school_contact_person` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `school_contact_phone` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `school_placements_placement_officer_id_foreign` (`placement_officer_id`),
  KEY `school_placements_client_id_status_index` (`client_id`,`status`),
  KEY `school_placements_school_id_index` (`school_id`),
  KEY `school_placements_status_index` (`status`),
  CONSTRAINT `school_placements_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE,
  CONSTRAINT `school_placements_placement_officer_id_foreign` FOREIGN KEY (`placement_officer_id`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `school_placements_school_id_foreign` FOREIGN KEY (`school_id`) REFERENCES `schools` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `schools`;
CREATE TABLE `schools` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `school_type` enum('special','regular','integrated') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'special',
  `registration_number` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `county_id` bigint unsigned NOT NULL,
  `sub_county_id` bigint unsigned DEFAULT NULL,
  `location` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `physical_address` text COLLATE utf8mb4_unicode_ci,
  `contact_person` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `phone` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `email` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `website` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `specializations` json DEFAULT NULL COMMENT 'Array of disabilities supported: vision_impairment, hearing_impairment, etc.',
  `boarding` tinyint(1) NOT NULL DEFAULT '0',
  `grades_offered` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'e.g., ECD-Grade 8, Form 1-4',
  `capacity` int DEFAULT NULL,
  `facilities` json DEFAULT NULL COMMENT 'Array of facilities: library, therapy_room, etc.',
  `support_services` json DEFAULT NULL COMMENT 'Array of services: braille, sign_language, etc.',
  `status` enum('active','inactive','pending_approval') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active',
  `notes` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `schools_registration_number_unique` (`registration_number`),
  KEY `schools_sub_county_id_foreign` (`sub_county_id`),
  KEY `schools_school_type_index` (`school_type`),
  KEY `schools_county_id_index` (`county_id`),
  KEY `schools_status_index` (`status`),
  CONSTRAINT `schools_county_id_foreign` FOREIGN KEY (`county_id`) REFERENCES `counties` (`id`),
  CONSTRAINT `schools_sub_county_id_foreign` FOREIGN KEY (`sub_county_id`) REFERENCES `sub_counties` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `service_bookings`;
CREATE TABLE `service_bookings` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `visit_id` bigint unsigned DEFAULT NULL,
  `client_id` bigint unsigned DEFAULT NULL,
  `service_id` bigint unsigned DEFAULT NULL,
  `department_id` bigint unsigned DEFAULT NULL,
  `booking_type` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'single',
  `booking_date` datetime DEFAULT NULL,
  `session_count` int DEFAULT '1',
  `estimated_duration` int DEFAULT NULL COMMENT 'Duration in minutes',
  `priority_level` int DEFAULT '3' COMMENT '1=High, 3=Normal, 5=Low',
  `payment_status` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `service_status` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'scheduled',
  `assigned_provider_id` bigint unsigned DEFAULT NULL,
  `insurance_provider_id` bigint unsigned DEFAULT NULL,
  `quantity` int DEFAULT '1',
  `unit_price` decimal(10,2) DEFAULT NULL,
  `total_price` decimal(10,2) DEFAULT NULL,
  `status` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `source` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `booked_by` bigint unsigned DEFAULT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `booked_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `service_bookings_booked_by_foreign` (`booked_by`),
  KEY `service_bookings_visit_id_index` (`visit_id`),
  KEY `service_bookings_client_id_index` (`client_id`),
  KEY `service_bookings_service_id_index` (`service_id`),
  KEY `service_bookings_department_id_index` (`department_id`),
  KEY `service_bookings_status_index` (`status`),
  KEY `service_bookings_assigned_provider_id_foreign` (`assigned_provider_id`),
  KEY `service_bookings_insurance_provider_id_foreign` (`insurance_provider_id`),
  CONSTRAINT `service_bookings_assigned_provider_id_foreign` FOREIGN KEY (`assigned_provider_id`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `service_bookings_booked_by_foreign` FOREIGN KEY (`booked_by`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `service_bookings_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE,
  CONSTRAINT `service_bookings_department_id_foreign` FOREIGN KEY (`department_id`) REFERENCES `departments` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `service_bookings_insurance_provider_id_foreign` FOREIGN KEY (`insurance_provider_id`) REFERENCES `insurance_providers` (`id`),
  CONSTRAINT `service_bookings_service_id_foreign` FOREIGN KEY (`service_id`) REFERENCES `services` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `service_bookings_visit_id_foreign` FOREIGN KEY (`visit_id`) REFERENCES `visits` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

