DROP TABLE IF EXISTS `service_insurance_prices`;
CREATE TABLE `service_insurance_prices` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `service_id` bigint unsigned NOT NULL,
  `insurance_provider_id` bigint unsigned NOT NULL,
  `covered_amount` decimal(10,2) NOT NULL,
  `client_copay` decimal(10,2) NOT NULL DEFAULT '0.00',
  `coverage_percentage` decimal(5,2) NOT NULL DEFAULT '100.00',
  `is_fully_covered` tinyint(1) NOT NULL DEFAULT '1',
  `requires_preauthorization` tinyint(1) NOT NULL DEFAULT '0',
  `preauthorization_code` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `effective_from` date DEFAULT NULL,
  `effective_to` date DEFAULT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `notes` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `sponsor_percentage` decimal(5,2) NOT NULL DEFAULT '100.00' COMMENT 'Percentage paid by sponsor (0-100)',
  `client_percentage` decimal(5,2) NOT NULL DEFAULT '0.00' COMMENT 'Percentage paid by client (0-100)',
  `client_copay_amount` decimal(10,2) DEFAULT NULL COMMENT 'Fixed copay amount (overrides percentage if set)',
  PRIMARY KEY (`id`),
  KEY `service_insurance_prices_service_id_foreign` (`service_id`),
  KEY `service_insurance_prices_insurance_provider_id_foreign` (`insurance_provider_id`),
  CONSTRAINT `service_insurance_prices_insurance_provider_id_foreign` FOREIGN KEY (`insurance_provider_id`) REFERENCES `insurance_providers` (`id`) ON DELETE CASCADE,
  CONSTRAINT `service_insurance_prices_service_id_foreign` FOREIGN KEY (`service_id`) REFERENCES `services` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

