DROP TABLE IF EXISTS `service_notes`;
CREATE TABLE `service_notes` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `service_session_id` bigint unsigned NOT NULL,
  `client_id` bigint unsigned NOT NULL,
  `provider_id` bigint unsigned NOT NULL,
  `note_type` enum('progress','clinical','administrative','safety','other') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'progress',
  `note_content` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `is_confidential` tinyint(1) NOT NULL DEFAULT '0',
  `is_locked` tinyint(1) NOT NULL DEFAULT '0',
  `locked_at` timestamp NULL DEFAULT NULL,
  `attachments` json DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `service_notes_service_session_id_index` (`service_session_id`),
  KEY `service_notes_client_id_index` (`client_id`),
  KEY `service_notes_provider_id_index` (`provider_id`),
  KEY `service_notes_note_type_index` (`note_type`),
  KEY `service_notes_is_confidential_index` (`is_confidential`),
  CONSTRAINT `service_notes_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE,
  CONSTRAINT `service_notes_provider_id_foreign` FOREIGN KEY (`provider_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `service_notes_service_session_id_foreign` FOREIGN KEY (`service_session_id`) REFERENCES `service_sessions` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `service_point_verifications`;
CREATE TABLE `service_point_verifications` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `visit_id` bigint unsigned NOT NULL,
  `client_id` bigint unsigned NOT NULL,
  `service_booking_id` bigint unsigned NOT NULL,
  `department_id` bigint unsigned NOT NULL,
  `verified_by` bigint unsigned NOT NULL,
  `verification_time` timestamp NOT NULL,
  `verification_status` enum('verified','payment_missing','wrong_department','service_unavailable','pending') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `payment_verified` tinyint(1) NOT NULL DEFAULT '0',
  `booking_verified` tinyint(1) NOT NULL DEFAULT '0',
  `routing_verified` tinyint(1) NOT NULL DEFAULT '0',
  `service_available` tinyint(1) NOT NULL DEFAULT '1',
  `provider_assigned_id` bigint unsigned DEFAULT NULL,
  `room_assigned` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `unavailability_reason` text COLLATE utf8mb4_unicode_ci,
  `rescheduled_to` timestamp NULL DEFAULT NULL,
  `sensitization_notes` text COLLATE utf8mb4_unicode_ci,
  `signed_in_at` timestamp NULL DEFAULT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `service_point_verifications_visit_id_foreign` (`visit_id`),
  KEY `service_point_verifications_client_id_foreign` (`client_id`),
  KEY `service_point_verifications_service_booking_id_foreign` (`service_booking_id`),
  KEY `service_point_verifications_department_id_foreign` (`department_id`),
  KEY `service_point_verifications_verified_by_foreign` (`verified_by`),
  KEY `service_point_verifications_provider_assigned_id_foreign` (`provider_assigned_id`),
  CONSTRAINT `service_point_verifications_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE,
  CONSTRAINT `service_point_verifications_department_id_foreign` FOREIGN KEY (`department_id`) REFERENCES `departments` (`id`) ON DELETE CASCADE,
  CONSTRAINT `service_point_verifications_provider_assigned_id_foreign` FOREIGN KEY (`provider_assigned_id`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `service_point_verifications_service_booking_id_foreign` FOREIGN KEY (`service_booking_id`) REFERENCES `service_bookings` (`id`) ON DELETE CASCADE,
  CONSTRAINT `service_point_verifications_verified_by_foreign` FOREIGN KEY (`verified_by`) REFERENCES `users` (`id`),
  CONSTRAINT `service_point_verifications_visit_id_foreign` FOREIGN KEY (`visit_id`) REFERENCES `visits` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `service_requests`;
CREATE TABLE `service_requests` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `visit_id` bigint unsigned NOT NULL,
  `client_id` bigint unsigned NOT NULL,
  `requested_by` bigint unsigned NOT NULL,
  `requesting_department_id` bigint unsigned NOT NULL,
  `service_id` bigint unsigned NOT NULL,
  `service_department_id` bigint unsigned NOT NULL,
  `request_type` enum('additional_service','lab','imaging','internal_referral','consultation','follow_up') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'additional_service',
  `priority` enum('routine','urgent','stat') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'routine',
  `status` enum('pending_payment','paid','in_queue','in_progress','completed','cancelled') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending_payment',
  `clinical_notes` text COLLATE utf8mb4_unicode_ci COMMENT 'Reason for request, clinical findings',
  `clinical_findings` text COLLATE utf8mb4_unicode_ci,
  `recommendations` text COLLATE utf8mb4_unicode_ci,
  `cost` decimal(10,2) NOT NULL,
  `payment_method` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `client_amount` decimal(10,2) DEFAULT NULL,
  `sponsor_amount` decimal(10,2) DEFAULT NULL,
  `service_booking_id` bigint unsigned DEFAULT NULL,
  `queue_entry_id` bigint unsigned DEFAULT NULL,
  `invoice_id` bigint unsigned DEFAULT NULL,
  `requested_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `paid_at` timestamp NULL DEFAULT NULL,
  `started_at` timestamp NULL DEFAULT NULL,
  `completed_at` timestamp NULL DEFAULT NULL,
  `cancelled_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `service_requests_requested_by_foreign` (`requested_by`),
  KEY `service_requests_requesting_department_id_foreign` (`requesting_department_id`),
  KEY `service_requests_service_id_foreign` (`service_id`),
  KEY `service_requests_service_booking_id_foreign` (`service_booking_id`),
  KEY `service_requests_queue_entry_id_foreign` (`queue_entry_id`),
  KEY `service_requests_invoice_id_foreign` (`invoice_id`),
  KEY `service_requests_visit_id_status_index` (`visit_id`,`status`),
  KEY `service_requests_client_id_status_index` (`client_id`,`status`),
  KEY `service_requests_service_department_id_status_index` (`service_department_id`,`status`),
  KEY `service_requests_status_index` (`status`),
  CONSTRAINT `service_requests_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE,
  CONSTRAINT `service_requests_invoice_id_foreign` FOREIGN KEY (`invoice_id`) REFERENCES `invoices` (`id`) ON DELETE SET NULL,
  CONSTRAINT `service_requests_queue_entry_id_foreign` FOREIGN KEY (`queue_entry_id`) REFERENCES `queue_entries` (`id`) ON DELETE SET NULL,
  CONSTRAINT `service_requests_requested_by_foreign` FOREIGN KEY (`requested_by`) REFERENCES `users` (`id`),
  CONSTRAINT `service_requests_requesting_department_id_foreign` FOREIGN KEY (`requesting_department_id`) REFERENCES `departments` (`id`),
  CONSTRAINT `service_requests_service_booking_id_foreign` FOREIGN KEY (`service_booking_id`) REFERENCES `service_bookings` (`id`) ON DELETE SET NULL,
  CONSTRAINT `service_requests_service_department_id_foreign` FOREIGN KEY (`service_department_id`) REFERENCES `departments` (`id`),
  CONSTRAINT `service_requests_service_id_foreign` FOREIGN KEY (`service_id`) REFERENCES `services` (`id`),
  CONSTRAINT `service_requests_visit_id_foreign` FOREIGN KEY (`visit_id`) REFERENCES `visits` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `service_sessions`;
CREATE TABLE `service_sessions` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `visit_id` bigint unsigned NOT NULL,
  `client_id` bigint unsigned NOT NULL,
  `service_booking_id` bigint unsigned NOT NULL,
  `service_id` bigint unsigned NOT NULL,
  `department_id` bigint unsigned NOT NULL,
  `provider_id` bigint unsigned NOT NULL,
  `signed_in_by` bigint unsigned DEFAULT NULL,
  `session_number` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `session_date` date NOT NULL,
  `start_time` time NOT NULL,
  `end_time` time DEFAULT NULL,
  `duration_minutes` int DEFAULT NULL,
  `baseline_assessment_data` json DEFAULT NULL,
  `intervention_plan` text COLLATE utf8mb4_unicode_ci,
  `status` enum('scheduled','in_progress','completed','cancelled','no_show') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'scheduled',
  `session_goals` text COLLATE utf8mb4_unicode_ci,
  `activities_performed` text COLLATE utf8mb4_unicode_ci,
  `client_response` text COLLATE utf8mb4_unicode_ci,
  `observations` text COLLATE utf8mb4_unicode_ci,
  `recommendations` text COLLATE utf8mb4_unicode_ci,
  `homework_assigned` text COLLATE utf8mb4_unicode_ci,
  `attendance` enum('present','absent','late') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `cancellation_reason` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `service_sessions_service_id_foreign` (`service_id`),
  KEY `service_sessions_department_id_foreign` (`department_id`),
  KEY `service_sessions_visit_id_index` (`visit_id`),
  KEY `service_sessions_client_id_index` (`client_id`),
  KEY `service_sessions_service_booking_id_index` (`service_booking_id`),
  KEY `service_sessions_provider_id_index` (`provider_id`),
  KEY `service_sessions_session_date_index` (`session_date`),
  KEY `service_sessions_status_index` (`status`),
  KEY `service_sessions_signed_in_by_foreign` (`signed_in_by`),
  CONSTRAINT `service_sessions_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE,
  CONSTRAINT `service_sessions_department_id_foreign` FOREIGN KEY (`department_id`) REFERENCES `departments` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `service_sessions_provider_id_foreign` FOREIGN KEY (`provider_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `service_sessions_service_booking_id_foreign` FOREIGN KEY (`service_booking_id`) REFERENCES `service_bookings` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `service_sessions_service_id_foreign` FOREIGN KEY (`service_id`) REFERENCES `services` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `service_sessions_signed_in_by_foreign` FOREIGN KEY (`signed_in_by`) REFERENCES `users` (`id`),
  CONSTRAINT `service_sessions_visit_id_foreign` FOREIGN KEY (`visit_id`) REFERENCES `visits` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `services`;
CREATE TABLE `services` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `code` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `department_id` bigint unsigned NOT NULL,
  `base_price` decimal(10,2) NOT NULL DEFAULT '0.00',
  `sha_covered` tinyint(1) NOT NULL DEFAULT '0',
  `sha_price` decimal(10,2) DEFAULT NULL,
  `ncpwd_covered` tinyint(1) NOT NULL DEFAULT '0',
  `ncpwd_price` decimal(10,2) DEFAULT NULL,
  `requires_assessment` tinyint(1) NOT NULL DEFAULT '0',
  `is_recurring` tinyint(1) NOT NULL DEFAULT '0',
  `duration_minutes` int DEFAULT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `available_from` date DEFAULT NULL,
  `available_until` date DEFAULT NULL,
  `category` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `subcategory` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `services_code_unique` (`code`),
  KEY `services_department_id_index` (`department_id`),
  KEY `services_is_active_index` (`is_active`),
  KEY `services_category_index` (`category`),
  KEY `services_code_index` (`code`),
  CONSTRAINT `services_department_id_foreign` FOREIGN KEY (`department_id`) REFERENCES `departments` (`id`) ON DELETE RESTRICT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

