DROP TABLE IF EXISTS `triage_red_flags`;
CREATE TABLE `triage_red_flags` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `triage_id` bigint unsigned NOT NULL,
  `flag_category` enum('respiratory','cardiovascular','neurological','trauma','behavioral','other') COLLATE utf8mb4_unicode_ci NOT NULL,
  `flag_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `severity` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'warning',
  `requires_immediate_attention` tinyint(1) DEFAULT '0',
  `action_taken` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `triage_red_flags_triage_id_index` (`triage_id`),
  KEY `triage_red_flags_flag_category_index` (`flag_category`),
  KEY `triage_red_flags_severity_index` (`severity`),
  CONSTRAINT `triage_red_flags_triage_id_foreign` FOREIGN KEY (`triage_id`) REFERENCES `triages` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

