DROP TABLE IF EXISTS `triages`;
CREATE TABLE `triages` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `triage_number` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `visit_id` bigint unsigned NOT NULL,
  `client_id` bigint unsigned NOT NULL,
  `branch_id` bigint unsigned NOT NULL,
  `temperature` decimal(4,1) DEFAULT NULL,
  `heart_rate` int DEFAULT NULL,
  `respiratory_rate` int DEFAULT NULL,
  `systolic_bp` int DEFAULT NULL,
  `diastolic_bp` int DEFAULT NULL,
  `oxygen_saturation` int DEFAULT NULL,
  `weight` decimal(6,2) DEFAULT NULL,
  `height` decimal(5,2) DEFAULT NULL,
  `bmi` decimal(5,2) DEFAULT NULL,
  `bmi_category` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pain_scale` int DEFAULT NULL,
  `consciousness_level` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'alert',
  `presenting_complaint` text COLLATE utf8mb4_unicode_ci,
  `risk_level` enum('low','medium','high') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'low',
  `risk_flag` enum('low','medium','high','crisis') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'low',
  `risk_score` int DEFAULT NULL,
  `has_red_flags` tinyint(1) NOT NULL DEFAULT '0',
  `safeguarding_concerns` json DEFAULT NULL,
  `has_safeguarding_concerns` tinyint(1) NOT NULL DEFAULT '0',
  `triage_status` enum('cleared','medical_hold','crisis') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'cleared',
  `clearance_status` enum('cleared_for_service','medical_hold','crisis_protocol') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'cleared_for_service',
  `next_step` enum('intake','payment','dispensary','crisis_team','service_point') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `routing_decision` enum('proceed_to_intake','immediate_dispensary','refer_emergency','defer') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'proceed_to_intake',
  `triage_notes` text COLLATE utf8mb4_unicode_ci,
  `handover_summary` text COLLATE utf8mb4_unicode_ci,
  `pending_actions` text COLLATE utf8mb4_unicode_ci,
  `crisis_protocol_activated` tinyint(1) NOT NULL DEFAULT '0',
  `crisis_activated_at` timestamp NULL DEFAULT NULL,
  `red_flags` json DEFAULT NULL,
  `triaged_by` bigint unsigned NOT NULL,
  `cleared_by` bigint unsigned DEFAULT NULL,
  `cleared_at` timestamp NULL DEFAULT NULL,
  `is_expired` tinyint(1) NOT NULL DEFAULT '0',
  `expires_at` timestamp NULL DEFAULT NULL,
  `triaged_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `triages_triaged_by_foreign` (`triaged_by`),
  KEY `triages_visit_id_index` (`visit_id`),
  KEY `triages_client_id_index` (`client_id`),
  KEY `triages_branch_id_index` (`branch_id`),
  KEY `triages_risk_level_index` (`risk_level`),
  KEY `triages_triage_status_index` (`triage_status`),
  KEY `triages_triaged_at_index` (`triaged_at`),
  KEY `triages_cleared_by_foreign` (`cleared_by`),
  CONSTRAINT `triages_branch_id_foreign` FOREIGN KEY (`branch_id`) REFERENCES `branches` (`id`) ON DELETE CASCADE,
  CONSTRAINT `triages_cleared_by_foreign` FOREIGN KEY (`cleared_by`) REFERENCES `users` (`id`),
  CONSTRAINT `triages_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE,
  CONSTRAINT `triages_triaged_by_foreign` FOREIGN KEY (`triaged_by`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `triages_visit_id_foreign` FOREIGN KEY (`visit_id`) REFERENCES `visits` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

