DROP VIEW IF EXISTS `v_active_credit_accounts`;
CREATE TABLE `v_active_credit_accounts` (`id` bigint unsigned, `account_number` varchar(255), `client_id` bigint unsigned, `client_name` varchar(201), `uci` varchar(50), `branch_id` bigint unsigned, `branch_name` varchar(150), `credit_limit` decimal(10,2), `current_balance` decimal(10,2), `available_credit` decimal(10,2), `utilization_percent` decimal(16,2), `status` enum('active','suspended','closed'), `created_at` timestamp);


DROP VIEW IF EXISTS `v_batch_invoice_summary`;
CREATE TABLE `v_batch_invoice_summary` (`id` bigint unsigned, `batch_number` varchar(50), `sponsor_type` enum('sha','ncpwd','insurance_private'), `insurance_provider` varchar(255), `billing_period_start` datetime, `billing_period_end` datetime, `total_claims` int, `total_amount` decimal(10,2), `paid_amount` decimal(10,2), `balance` decimal(10,2), `status` enum('draft','submitted','approved','paid','partial','rejected'), `sent_at` timestamp, `due_date` datetime, `days_overdue` int);


DROP VIEW IF EXISTS `v_credit_transactions_summary`;
CREATE TABLE `v_credit_transactions_summary` (`id` bigint unsigned, `transaction_number` varchar(255), `credit_account_id` bigint unsigned, `account_number` varchar(255), `client_id` bigint unsigned, `client_name` varchar(201), `type` enum('charge','payment','adjustment','refund'), `amount` decimal(10,2), `balance_before` decimal(10,2), `balance_after` decimal(10,2), `description` text, `transaction_date` timestamp, `processed_by_name` varchar(255), `created_at` timestamp);


DROP VIEW IF EXISTS `v_invoice_payment_breakdown`;
CREATE TABLE `v_invoice_payment_breakdown` (`invoice_id` bigint unsigned, `invoice_number` varchar(50), `total_amount` decimal(10,2), `total_client_amount` decimal(10,2), `total_sponsor_amount` decimal(10,2), `client_payment_status` varchar(200), `sponsor_claim_status` varchar(200), `has_sponsor` tinyint(1), `client_name` varchar(201), `client_uci` varchar(50), `visit_number` varchar(50), `claim_number` varchar(255), `sponsor_type` varchar(100), `claim_status` varchar(200), `claim_amount` decimal(12,2), `approved_amount` decimal(12,2), `paid_amount` decimal(12,2));


DROP VIEW IF EXISTS `v_monthly_claims_summary`;
CREATE TABLE `v_monthly_claims_summary` (`sponsor_type` varchar(100), `month` varchar(7), `total_claims` bigint, `total_claimed` decimal(34,2), `total_approved` decimal(34,2), `total_paid` decimal(34,2), `total_rejected` decimal(34,2), `total_pending` decimal(34,2));


DROP VIEW IF EXISTS `v_pending_claims_summary`;
CREATE TABLE `v_pending_claims_summary` (`sponsor_type` varchar(100), `total_claims` bigint, `total_amount` decimal(34,2), `oldest_claim` datetime, `newest_claim` datetime);


DROP TABLE IF EXISTS `visit_stages`;
CREATE TABLE `visit_stages` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `visit_id` bigint unsigned NOT NULL,
  `stage` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `started_at` timestamp NULL DEFAULT NULL,
  `completed_at` timestamp NULL DEFAULT NULL,
  `duration_minutes` int DEFAULT NULL,
  `handled_by` bigint unsigned DEFAULT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `visit_stages_handled_by_foreign` (`handled_by`),
  KEY `visit_stages_visit_id_index` (`visit_id`),
  KEY `visit_stages_stage_index` (`stage`),
  KEY `visit_stages_status_index` (`status`),
  CONSTRAINT `visit_stages_handled_by_foreign` FOREIGN KEY (`handled_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `visit_stages_visit_id_foreign` FOREIGN KEY (`visit_id`) REFERENCES `visits` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

