DROP TABLE IF EXISTS `visits`;
CREATE TABLE `visits` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `branch_id` bigint unsigned NOT NULL,
  `client_id` bigint unsigned NOT NULL,
  `visit_number` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `visit_date` date NOT NULL,
  `visit_type` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT (_utf8mb4'walk_in'),
  `visit_purpose` text COLLATE utf8mb4_unicode_ci,
  `referral_source` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `is_appointment` tinyint(1) DEFAULT '0',
  `is_emergency` tinyint(1) DEFAULT '0',
  `requires_followup` tinyint(1) DEFAULT NULL,
  `service_available` tinyint(1) DEFAULT NULL,
  `unavailability_reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `purpose_notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `unavailability_notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `triage_path` enum('standard','medical_veto','crisis') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `current_stage` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'reception',
  `payment_status` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` enum('open','checked_in','in_triage','in_intake','awaiting_payment','in_queue','in_service','completed','deferred','cancelled','in_progress') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'open',
  `chief_complaint` text COLLATE utf8mb4_unicode_ci,
  `check_in_time` timestamp NULL DEFAULT NULL,
  `check_out_time` timestamp NULL DEFAULT NULL,
  `checked_in_by` bigint unsigned DEFAULT NULL,
  `completed_at` timestamp NULL DEFAULT NULL,
  `payment_verified_at` datetime DEFAULT NULL,
  `completed_by` bigint unsigned DEFAULT NULL,
  `deferred_at` timestamp NULL DEFAULT NULL,
  `deferred_reason` text COLLATE utf8mb4_unicode_ci,
  `total_services` int DEFAULT '0',
  `completed_services` int DEFAULT '0',
  `total_amount` decimal(10,2) DEFAULT '0.00',
  `paid_amount` decimal(10,2) DEFAULT '0.00',
  `notes` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `visits_visit_number_unique` (`visit_number`),
  KEY `visits_checked_in_by_foreign` (`checked_in_by`),
  KEY `visits_completed_by_foreign` (`completed_by`),
  KEY `visits_branch_id_index` (`branch_id`),
  KEY `visits_client_id_index` (`client_id`),
  KEY `visits_visit_date_index` (`visit_date`),
  KEY `visits_status_index` (`status`),
  KEY `visits_current_stage_index` (`current_stage`),
  KEY `visits_visit_number_index` (`visit_number`),
  CONSTRAINT `visits_branch_id_foreign` FOREIGN KEY (`branch_id`) REFERENCES `branches` (`id`) ON DELETE CASCADE,
  CONSTRAINT `visits_checked_in_by_foreign` FOREIGN KEY (`checked_in_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `visits_client_id_foreign` FOREIGN KEY (`client_id`) REFERENCES `clients` (`id`) ON DELETE CASCADE,
  CONSTRAINT `visits_completed_by_foreign` FOREIGN KEY (`completed_by`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

