DROP TABLE IF EXISTS `v_active_credit_accounts`;
CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `v_active_credit_accounts` AS select `ca`.`id` AS `id`,`ca`.`account_number` AS `account_number`,`ca`.`client_id` AS `client_id`,concat(`c`.`first_name`,' ',`c`.`last_name`) AS `client_name`,`c`.`uci` AS `uci`,`ca`.`branch_id` AS `branch_id`,`b`.`name` AS `branch_name`,`ca`.`credit_limit` AS `credit_limit`,`ca`.`current_balance` AS `current_balance`,`ca`.`available_credit` AS `available_credit`,round(((`ca`.`current_balance` / `ca`.`credit_limit`) * 100),2) AS `utilization_percent`,`ca`.`status` AS `status`,`ca`.`created_at` AS `created_at` from ((`client_credit_accounts` `ca` join `clients` `c` on((`ca`.`client_id` = `c`.`id`))) join `branches` `b` on((`ca`.`branch_id` = `b`.`id`))) where (`ca`.`deleted_at` is null);

DROP TABLE IF EXISTS `v_batch_invoice_summary`;
CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `v_batch_invoice_summary` AS select `biv`.`id` AS `id`,`biv`.`batch_number` AS `batch_number`,`biv`.`sponsor_type` AS `sponsor_type`,`ip`.`name` AS `insurance_provider`,`biv`.`billing_period_start` AS `billing_period_start`,`biv`.`billing_period_end` AS `billing_period_end`,`biv`.`total_claims` AS `total_claims`,`biv`.`total_amount` AS `total_amount`,`biv`.`paid_amount` AS `paid_amount`,`biv`.`balance` AS `balance`,`biv`.`status` AS `status`,`biv`.`sent_at` AS `sent_at`,`biv`.`due_date` AS `due_date`,(to_days(curdate()) - to_days(`biv`.`due_date`)) AS `days_overdue` from (`insurance_batch_invoices` `biv` left join `insurance_providers` `ip` on((`biv`.`insurance_provider_id` = `ip`.`id`))) where (`biv`.`deleted_at` is null);

DROP TABLE IF EXISTS `v_credit_transactions_summary`;
CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `v_credit_transactions_summary` AS select `ct`.`id` AS `id`,`ct`.`transaction_number` AS `transaction_number`,`ct`.`credit_account_id` AS `credit_account_id`,`ca`.`account_number` AS `account_number`,`ca`.`client_id` AS `client_id`,concat(`c`.`first_name`,' ',`c`.`last_name`) AS `client_name`,`ct`.`type` AS `type`,`ct`.`amount` AS `amount`,`ct`.`balance_before` AS `balance_before`,`ct`.`balance_after` AS `balance_after`,`ct`.`description` AS `description`,`ct`.`transaction_date` AS `transaction_date`,`u`.`name` AS `processed_by_name`,`ct`.`created_at` AS `created_at` from (((`credit_transactions` `ct` join `client_credit_accounts` `ca` on((`ct`.`credit_account_id` = `ca`.`id`))) join `clients` `c` on((`ca`.`client_id` = `c`.`id`))) left join `users` `u` on((`ct`.`processed_by` = `u`.`id`))) where (`ct`.`deleted_at` is null);

DROP TABLE IF EXISTS `v_invoice_payment_breakdown`;
CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `v_invoice_payment_breakdown` AS select `i`.`id` AS `invoice_id`,`i`.`invoice_number` AS `invoice_number`,`i`.`total_amount` AS `total_amount`,`i`.`total_client_amount` AS `total_client_amount`,`i`.`total_sponsor_amount` AS `total_sponsor_amount`,`i`.`client_payment_status` AS `client_payment_status`,`i`.`sponsor_claim_status` AS `sponsor_claim_status`,`i`.`has_sponsor` AS `has_sponsor`,concat(`c`.`first_name`,' ',`c`.`last_name`) AS `client_name`,`c`.`uci` AS `client_uci`,`v`.`visit_number` AS `visit_number`,`ic`.`claim_number` AS `claim_number`,`ic`.`sponsor_type` AS `sponsor_type`,`ic`.`status` AS `claim_status`,`ic`.`claim_amount` AS `claim_amount`,`ic`.`approved_amount` AS `approved_amount`,`ic`.`paid_amount` AS `paid_amount` from (((`invoices` `i` join `clients` `c` on((`i`.`client_id` = `c`.`id`))) join `visits` `v` on((`i`.`visit_id` = `v`.`id`))) left join `insurance_claims` `ic` on((`i`.`id` = `ic`.`invoice_id`))) where (`i`.`deleted_at` is null);

DROP TABLE IF EXISTS `v_monthly_claims_summary`;
CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `v_monthly_claims_summary` AS select `insurance_claims`.`sponsor_type` AS `sponsor_type`,date_format(`insurance_claims`.`service_date`,'%Y-%m') AS `month`,count(0) AS `total_claims`,sum(`insurance_claims`.`claim_amount`) AS `total_claimed`,sum(`insurance_claims`.`approved_amount`) AS `total_approved`,sum(`insurance_claims`.`paid_amount`) AS `total_paid`,sum(`insurance_claims`.`rejection_amount`) AS `total_rejected`,sum((case when (`insurance_claims`.`status` in ('pending','submitted','under_review')) then `insurance_claims`.`claim_amount` else 0 end)) AS `total_pending` from `insurance_claims` where (`insurance_claims`.`deleted_at` is null) group by `insurance_claims`.`sponsor_type`,date_format(`insurance_claims`.`service_date`,'%Y-%m') order by `month` desc,`insurance_claims`.`sponsor_type`;

DROP TABLE IF EXISTS `v_pending_claims_summary`;
CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `v_pending_claims_summary` AS select `insurance_claims`.`sponsor_type` AS `sponsor_type`,count(0) AS `total_claims`,sum(`insurance_claims`.`claim_amount`) AS `total_amount`,min(`insurance_claims`.`service_date`) AS `oldest_claim`,max(`insurance_claims`.`service_date`) AS `newest_claim` from `insurance_claims` where ((`insurance_claims`.`status` in ('pending','submitted')) and (`insurance_claims`.`deleted_at` is null)) group by `insurance_claims`.`sponsor_type`;

-- 2026-03-19 08:25:54 UTC
